import React from "react";
import bootstrap from "bootstrap";
import "../login/style.css"

const Login = () => {
  return (
    <>
      <section className="container">
        <div className="sub_container">
          <div className="login_heading "></div>
          <div className="login_text__box"></div>
          <div className="l_password"></div>
          <div className="login_text__box2"></div>
          <div className="login_text__box3"></div>
          <div className=""></div>
        </div>
      </section>
    </>
  );
};
export default Login;
